INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('fire-eq-tech-moex-02730', 'fire-eq-tech', 'fire-eq-tech-moex-099-99dbadc8', 'sub-fire-eq-tech-04', NULL, 'single_choice', '進行避難器具開口部外觀檢查時，下列敘述何者錯誤？', '["開口部應加設固定板、木條等", "由地板面至開口部下端之高度應在150 cm以下", "緩降機之開口部高80 cm以上，寬50 cm以上或高100 cm以上，寬45 cm以上", "開口部太高可能形成避難上之障礙時，應設有固定式或半固定式之踏台"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:25+00:00", "source_pdf_sha1": "55e73ee84279", "answer_pdf_sha1": "5458d160a3a4", "source_family": "moex-gov-tw", "moex": {"exam_code": "099080", "c": "701", "s": "300", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "警報與避難系統消防安全設備概要", "year": "099", "exam_name": "099年專技消防設備人員、地政士、專責報關、保險人員、特考中醫、語言治療、聽力考試", "original_question_number": 2, "answer_corrected": false, "flags": ["answer_missing"], "slug": "fire-equipment-technician", "db_exam_id": "fire-eq-tech"}'::jsonb, NULL),
  ('fire-eq-tech-moex-02731', 'fire-eq-tech', 'fire-eq-tech-moex-099-99dbadc8', 'sub-fire-eq-tech-04', NULL, 'single_choice', '下列有關差動式探測器之敘述何者為錯誤？', '["差動式局限型探測器下端，裝設在裝置面下方三十公分範圍內", "對於未滿四公尺防火構造建築物，差動式局限型一種探測器之有效探測範圍為45平方公尺", "差動式分布型探測器為空氣管式時，每一探測區域內之空氣管長度，露出部分在二十公尺以上", "差動式分布型探測器為空氣管式時，裝接於一個檢出器之空氣管長度，在一百公尺以下"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:25+00:00", "source_pdf_sha1": "55e73ee84279", "answer_pdf_sha1": "5458d160a3a4", "source_family": "moex-gov-tw", "moex": {"exam_code": "099080", "c": "701", "s": "300", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "警報與避難系統消防安全設備概要", "year": "099", "exam_name": "099年專技消防設備人員、地政士、專責報關、保險人員、特考中醫、語言治療、聽力考試", "original_question_number": 3, "answer_corrected": false, "flags": ["answer_missing"], "slug": "fire-equipment-technician", "db_exam_id": "fire-eq-tech"}'::jsonb, NULL),
  ('fire-eq-tech-moex-02732', 'fire-eq-tech', 'fire-eq-tech-moex-099-99dbadc8', 'sub-fire-eq-tech-04', NULL, 'single_choice', '下列有關火警受信總機之敘述何者為錯誤？', '["受信總機、中繼器及偵煙式探測器，有設定蓄積時間時，其蓄積時間之合計，每一火警分區在二十秒 以下", "裝置蓄積式探測器或中繼器之火警分區，該分區在受信總機，不得有雙信號功能", "壁掛型總機操作開關距離樓地板面之高度，在零點八公尺以上一點五公尺以下", "Ｐ型受信總機採用數個分區共用一公用線方式配線時，該公用線供應之分區數，不得超過七個"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:25+00:00", "source_pdf_sha1": "55e73ee84279", "answer_pdf_sha1": "5458d160a3a4", "source_family": "moex-gov-tw", "moex": {"exam_code": "099080", "c": "701", "s": "300", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "警報與避難系統消防安全設備概要", "year": "099", "exam_name": "099年專技消防設備人員、地政士、專責報關、保險人員、特考中醫、語言治療、聽力考試", "original_question_number": 4, "answer_corrected": false, "flags": ["answer_missing"], "slug": "fire-equipment-technician", "db_exam_id": "fire-eq-tech"}'::jsonb, NULL),
  ('fire-eq-tech-moex-02733', 'fire-eq-tech', 'fire-eq-tech-moex-099-99dbadc8', 'sub-fire-eq-tech-04', NULL, 'single_choice', '下列有關緊急廣播設備之敘述，何者為錯誤？', '["各樓層任一點至啟動裝置之步行距離在五十公尺以下", "每一廣播分區不得超過一樓層，惟上下兩樓層面積合計小於六百平方公尺，可設為同一廣播分區", "各類場所第十一層以上之各樓層、地下第三層以下之各樓層或地下建築物，應使用緊急電話方式啟動", "廣播區域超過一百平方公尺時，設Ｌ級揚聲器"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:25+00:00", "source_pdf_sha1": "55e73ee84279", "answer_pdf_sha1": "5458d160a3a4", "source_family": "moex-gov-tw", "moex": {"exam_code": "099080", "c": "701", "s": "300", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "警報與避難系統消防安全設備概要", "year": "099", "exam_name": "099年專技消防設備人員、地政士、專責報關、保險人員、特考中醫、語言治療、聽力考試", "original_question_number": 5, "answer_corrected": false, "flags": ["answer_missing"], "slug": "fire-equipment-technician", "db_exam_id": "fire-eq-tech"}'::jsonb, NULL),
  ('fire-eq-tech-moex-02734', 'fire-eq-tech', 'fire-eq-tech-moex-099-99dbadc8', 'sub-fire-eq-tech-04', NULL, 'single_choice', '下列有關進行緊急廣播設備檢查，下列敘述何者錯誤？', '["與一般廣播兼用時，於一般廣播狀態，進行緊急廣播時，應確實切換成緊急廣播", "與火警自動警報設備之連動時，於受信火災信號後，自動地啟動廣播設備，其火災音響信號或音響裝 置應鳴動", "距揚聲器一公尺處，使用噪音計（Ａ特性），確認揚聲器之音壓，Ｌ級90分貝以上", "若採分區鳴動，起火層為地面層時，限該樓層與其直上層及地下層各層鳴動"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:25+00:00", "source_pdf_sha1": "55e73ee84279", "answer_pdf_sha1": "5458d160a3a4", "source_family": "moex-gov-tw", "moex": {"exam_code": "099080", "c": "701", "s": "300", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "警報與避難系統消防安全設備概要", "year": "099", "exam_name": "099年專技消防設備人員、地政士、專責報關、保險人員、特考中醫、語言治療、聽力考試", "original_question_number": 6, "answer_corrected": false, "flags": ["answer_missing"], "slug": "fire-equipment-technician", "db_exam_id": "fire-eq-tech"}'::jsonb, NULL),
  ('fire-eq-tech-moex-02735', 'fire-eq-tech', 'fire-eq-tech-moex-099-99dbadc8', 'sub-fire-eq-tech-04', NULL, 'single_choice', '下列有關手動報警設備之敘述，何者錯誤？', '["火警發信機之按鈕按下時，能有二十秒蓄積時間才發出火警音響，避免誤動作的產生", "二樓層共用一火警分區者，火警發信機應分別設置", "其標示燈與裝置面成十五度角，在十公尺距離內須無遮視物且明顯易見", "建築物內裝有消防立管之消防栓箱時，火警發信機、標示燈及火警警鈴裝設在消防栓箱上方牆上"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:25+00:00", "source_pdf_sha1": "55e73ee84279", "answer_pdf_sha1": "5458d160a3a4", "source_family": "moex-gov-tw", "moex": {"exam_code": "099080", "c": "701", "s": "300", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "警報與避難系統消防安全設備概要", "year": "099", "exam_name": "099年專技消防設備人員、地政士、專責報關、保險人員、特考中醫、語言治療、聽力考試", "original_question_number": 7, "answer_corrected": false, "flags": ["answer_missing"], "slug": "fire-equipment-technician", "db_exam_id": "fire-eq-tech"}'::jsonb, NULL),
  ('fire-eq-tech-moex-02736', 'fire-eq-tech', 'fire-eq-tech-moex-099-99dbadc8', 'sub-fire-eq-tech-04', NULL, 'single_choice', '探測器之裝置場所高度為10公尺時，下列那一種探測器不適合安裝？', '["差動式分布型", "火焰式", "補償式局限型", "光電式分離型"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:25+00:00", "source_pdf_sha1": "55e73ee84279", "answer_pdf_sha1": "5458d160a3a4", "source_family": "moex-gov-tw", "moex": {"exam_code": "099080", "c": "701", "s": "300", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "警報與避難系統消防安全設備概要", "year": "099", "exam_name": "099年專技消防設備人員、地政士、專責報關、保險人員、特考中醫、語言治療、聽力考試", "original_question_number": 8, "answer_corrected": false, "flags": ["answer_missing"], "slug": "fire-equipment-technician", "db_exam_id": "fire-eq-tech"}'::jsonb, NULL),
  ('fire-eq-tech-moex-02737', 'fire-eq-tech', 'fire-eq-tech-moex-099-99dbadc8', 'sub-fire-eq-tech-04', NULL, 'single_choice', '偵煙式探測器之探測區域，指探測器裝置面之四周以淨高多少公分以上之樑或類似構造體區劃包圍者？', '["30", "40", "60", "80"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:25+00:00", "source_pdf_sha1": "55e73ee84279", "answer_pdf_sha1": "5458d160a3a4", "source_family": "moex-gov-tw", "moex": {"exam_code": "099080", "c": "701", "s": "300", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "警報與避難系統消防安全設備概要", "year": "099", "exam_name": "099年專技消防設備人員、地政士、專責報關、保險人員、特考中醫、語言治療、聽力考試", "original_question_number": 9, "answer_corrected": false, "flags": ["answer_missing"], "slug": "fire-equipment-technician", "db_exam_id": "fire-eq-tech"}'::jsonb, NULL),
  ('fire-eq-tech-moex-02738', 'fire-eq-tech', 'fire-eq-tech-moex-099-99dbadc8', 'sub-fire-eq-tech-04', NULL, 'single_choice', '下列有關緊急照明燈之規定何者錯誤？', '["在避難層，由居室任一點至通往屋外出口之步行距離在三十公尺以下之居室得免設緊急照明燈", "緊急照明設備應連接緊急電源使用蓄電池設備，其容量應能使其持續動作三十分鐘以上", "日光燈為瞬時起動型，其燈座為耐熱絕緣樹脂製成者", "緊急照明燈在地面之水平面照度，在地下建築物之地下通道，其地板面應在二勒克司（Lux）以上"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:25+00:00", "source_pdf_sha1": "55e73ee84279", "answer_pdf_sha1": "5458d160a3a4", "source_family": "moex-gov-tw", "moex": {"exam_code": "099080", "c": "701", "s": "300", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "警報與避難系統消防安全設備概要", "year": "099", "exam_name": "099年專技消防設備人員、地政士、專責報關、保險人員、特考中醫、語言治療、聽力考試", "original_question_number": 10, "answer_corrected": false, "flags": ["answer_missing"], "slug": "fire-equipment-technician", "db_exam_id": "fire-eq-tech"}'::jsonb, NULL),
  ('fire-eq-tech-moex-02739', 'fire-eq-tech', 'fire-eq-tech-moex-099-99dbadc8', 'sub-fire-eq-tech-04', NULL, 'single_choice', '差動式分布型探測器為空氣管式時，其間距，在防火構造建築物，在多少公尺以下？', '["3", "6", "9", "12"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:25+00:00", "source_pdf_sha1": "55e73ee84279", "answer_pdf_sha1": "5458d160a3a4", "source_family": "moex-gov-tw", "moex": {"exam_code": "099080", "c": "701", "s": "300", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "警報與避難系統消防安全設備概要", "year": "099", "exam_name": "099年專技消防設備人員、地政士、專責報關、保險人員、特考中醫、語言治療、聽力考試", "original_question_number": 11, "answer_corrected": false, "flags": ["answer_missing"], "slug": "fire-equipment-technician", "db_exam_id": "fire-eq-tech"}'::jsonb, NULL)
